{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOTusz8soMH/GJYxKmSKNwD"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"FDgTpmvNlvOE"},"outputs":[],"source":["\"\"\"\n","Data Extraction Script for Bitcoin DCC-GARCH Project\n","Author: Ian Schlagel\n","Description: Downloads daily closing prices for Bitcoin and the S&P 500\n","             from Yahoo Finance for use in Stata analysis.\n","\"\"\"\n","\n","import yfinance as yf\n","from google.colab import files # Remove this line if not using Colab\n","\n","# 1. Define Tickers (Bitcoin & S&P 500)\n","tickers = [\"BTC-USD\", \"^GSPC\"]\n","\n","# 2. Set Date Range\n","start_date = \"2020-01-01\"\n","end_date = \"2025-11-10\"\n","\n","# 3. Download Data\n","print(f\"Downloading data for {tickers}...\")\n","data = yf.download(tickers, start=start_date, end=end_date)['Close']\n","\n","# 4. Save to CSV\n","output_file = \"macro_data.csv\"\n","data.to_csv(output_file)\n","print(f\"Success! {output_file} created.\")\n"]},{"cell_type":"code","source":[],"metadata":{"id":"Wh0KP7oJoX6h"},"execution_count":null,"outputs":[]}]}